+  lastProcessed: RetryMutationResult | null,
+  toastApi: ToastApi,
+  navigate: (path: string) => void,
+): RetryMutationResult | null {
+  if (!result || lastProcessed === result) return lastProcessed;
+  if (result.ok === true) {
+    toastApi.push({ message: "Retry started." });
